    22→type FlowState = "loading" | "questions" | "submitting" | "result";
    23→
    24→export function EnrichmentFlow({ analysis, scores, decision, ideaId, ideaSummary, onComplete, onCancel }: EnrichmentFlowProps) {
    25→    const { t } = useLanguageStore();
    26→    const [state, setState] = useState<FlowState>("loading");
    27→    const [questions, setQuestions] = useState<EnrichmentQuestion[]>([]);
    28→    const [enrichmentId, setEnrichmentId] = useState<string>("");
    29→    const [currentIndex, setCurrentIndex] = useState(0);
    30→    const [responses, setResponses] = useState<Map<string, EnrichmentResponse>>(new Map());
    31→    const [selectedOptions, setSelectedOptions] = useState<Set<string>>(new Set());
    32→    const [recalcResult, setRecalcResult] = useState<any>(null);
    33→
    34→    // Generate questions on mount
    35→    useEffect(() => {
    36→        generateQuestions();
    37→        // eslint-disable-next-line react-hooks/exhaustive-deps
    38→    }, []);
    39→
    40→    async function generateQuestions() {
    41→        setState("loading");
    42→        try {
    43→            const res = await fetch("/api/enrichment", {
    44→                method: "POST",
    45→                headers: { "Content-Type": "application/json" },
    46→                body: JSON.stringify({
    47→                    action: "generate",
    48→                    idea_id: ideaId,
    49→                    idea_summary: ideaSummary,
    50→                    analysis,
    51→                    scores: { global_score: scores.global_score },
    52→                    decision: {
    53→                        recommendation: decision.recommendation,
    54→                        confidence_level: decision.confidence_level,
    55→                    },
    56→                }),
    57→            });
    58→
    59→            const data = await res.json();
    60→            if (!res.ok) throw new Error(data.error?.message || "Failed to generate questions");
    61→
    62→            if (!data.required || !data.questions?.length) {
    63→                toast.info(t?.analysis?.enrichment?.notNeeded || "No enrichment needed");
    64→                onCancel();
    65→                return;
    66→            }
    67→
    68→            setEnrichmentId(data.enrichment_id);
    69→            setQuestions(data.questions);
    70→            setState("questions");
    71→        } catch (error: any) {
    72→            console.error("Enrichment generation failed:", error);
    73→            toast.error(t?.analysis?.enrichment?.generateFailed || "Could not generate questions");
    74→            onCancel();
    75→        }
    76→    }
    77→
    78→    function handleSelectOption(optionId: string, isMulti: boolean) {
    79→        setSelectedOptions((prev) => {
    80→            const next = new Set(prev);
    81→            if (isMulti) {
    82→                if (next.has(optionId)) next.delete(optionId);
    83→                else next.add(optionId);
    84→            } else {
    85→                next.clear();
    86→                next.add(optionId);
    87→            }
    88→            return next;
    89→        });
    90→    }
    91→
    92→    function confirmAnswer() {
    93→        const question = questions[currentIndex];
    94→        const response: EnrichmentResponse = {
    95→            question_id: question.question_id,
    96→            status: "completed",
    97→            selected_option_ids: Array.from(selectedOptions),
    98→        };
    99→        setResponses((prev) => new Map(prev).set(question.question_id, response));
   100→        advance();
   101→    }
   102→
   103→    function skipQuestion() {
   104→        const question = questions[currentIndex];
   105→        const response: EnrichmentResponse = {
   106→            question_id: question.question_id,
   107→            status: "skipped",
   108→        };
