   244→                    <div className="flex justify-center pt-4">
   245→                        <Button
   246→                            onClick={() => onComplete(recalcResult)}
   247→                            className="bg-[#F75105] hover:bg-[#F78E21] text-white font-medium px-8"
   248→                        >
   249→                            <CheckCircle2 className="w-4 h-4 mr-2" />
   250→                            {t?.analysis?.enrichment?.apply || "Apply & Continue"}
   251→                        </Button>
   252→                    </div>
   253→                </div>
   254→            </div>
   255→        );
   256→    }
   257→
   258→    // Questions state
   259→    const question = questions[currentIndex];
   260→    if (!question) return null;
   261→    const isMulti = question.type === "multi_select";
   262→    const progress = ((currentIndex + 1) / questions.length) * 100;
   263→
   264→    return (
   265→        <div className="bg-[#2F323A] rounded-xl border-0 overflow-hidden ring-1 ring-white/5 animate-in zoom-in-95 duration-500">
   266→            <div className="p-8 space-y-6">
   267→                {/* Header */}
   268→                <div className="flex items-center justify-between">
   269→                    <button onClick={onCancel} className="text-gray-500 hover:text-white transition-colors flex items-center gap-2 text-sm">
   270→                        <ArrowLeft className="w-4 h-4" />
   271→                        {t?.analysis?.enrichment?.back || "Back to results"}
   272→                    </button>
   273→                    <span className="text-[10px] text-gray-500 uppercase tracking-widest">
   274→                        {currentIndex + 1} / {questions.length}
   275→                    </span>
   276→                </div>
   277→
   278→                {/* Progress */}
   279→                <div className="w-full h-1 bg-[#3A3D45] rounded-full overflow-hidden">
   280→                    <div className="h-full bg-[#F75105] transition-all duration-300" style={{ width: `${progress}%` }} />
   281→                </div>
   282→
   283→                {/* Axis Tag */}
   284→                <div className="flex items-center gap-2">
   285→                    <span className="text-[10px] font-bold text-[#F75105] uppercase tracking-widest bg-[#F75105]/10 px-3 py-1 rounded-full border border-[#F75105]/20">
   286→                        {question.axis.replace("_", " ")}
   287→                    </span>
   288→                    {isMulti && (
   289→                        <span className="text-[10px] text-gray-500 uppercase tracking-wider">
   290→                            {t?.analysis?.enrichment?.multiSelect || "Select multiple"}
   291→                        </span>
   292→                    )}
   293→                </div>
   294→
   295→                {/* Question */}
   296→                <h3 className="text-xl font-medium text-white leading-relaxed">
   297→                    {question.prompt}
   298→                </h3>
   299→
   300→                {/* Options */}
   301→                <div className="space-y-3">
   302→                    {question.options.map((option) => {
   303→                        const selected = selectedOptions.has(option.id);
   304→                        return (
   305→                            <button
   306→                                key={option.id}
   307→                                onClick={() => handleSelectOption(option.id, isMulti)}
   308→                                className={cn(
   309→                                    "w-full text-left p-4 rounded-lg border transition-all duration-200",
   310→                                    selected
   311→                                        ? "bg-[#F75105]/10 border-[#F75105]/40 text-white"
   312→                                        : "bg-[#22242B]/50 border-white/5 text-gray-300 hover:border-[#F75105]/20 hover:bg-[#22242B]"
   313→                                )}
   314→                            >
   315→                                <div className="flex items-center gap-3">
   316→                                    <div className={cn(
   317→                                        "w-5 h-5 rounded-full border-2 flex items-center justify-center shrink-0 transition-colors",
   318→                                        selected ? "border-[#F75105] bg-[#F75105]" : "border-gray-600"
   319→                                    )}>
   320→                                        {selected && <CheckCircle2 className="w-3 h-3 text-white" />}
   321→                                    </div>
   322→                                    <span className="text-sm">{option.label}</span>
   323→                                </div>
   324→                            </button>
   325→                        );
   326→                    })}
   327→                </div>
   328→
   329→                {/* Actions */}
   330→                <div className="flex items-center justify-between pt-4 border-t border-[#3A3D45]">
   331→                    {question.allow_skip && (
   332→                        <Button
   333→                            variant="ghost"
   334→                            onClick={skipQuestion}
   335→                            className="text-gray-500 hover:text-white"
   336→                        >
   337→                            <SkipForward className="w-4 h-4 mr-2" />
   338→                            {t?.analysis?.enrichment?.skip || "Skip"}
   339→                        </Button>
   340→                    )}
   341→                    <div className="flex-1" />
   342→                    <Button
   343→                        onClick={confirmAnswer}
   344→                        disabled={selectedOptions.size === 0}
   345→                        className={cn(
   346→                            "px-6",
   347→                            selectedOptions.size > 0
   348→                                ? "bg-[#F75105] hover:bg-[#F78E21] text-white"
   349→                                : "bg-[#3A3D45] text-gray-500 cursor-not-allowed"
   350→                        )}
   351→                    >
   352→                        {currentIndex < questions.length - 1
   353→                            ? (t?.analysis?.enrichment?.next || "Next")
   354→                            : (t?.analysis?.enrichment?.submit || "Submit")
   355→                        }
   356→                        <ArrowRight className="w-4 h-4 ml-2" />
   357→                    </Button>
   358→                </div>
   359→            </div>
   360→        </div>
   361→    );
   362→}
