     1→/**
     2→ * K3RN.LABS — POST /api/analysis
     3→ * Analyse canonique d'une idée via OpenAI API
     4→ *
     5→ * Pipeline :
     6→ * 1. Validation input (JSON Schema)
     7→ * 2. Assemblage prompt (system + orchestrator + experts + constraints)
     8→ * 3. Appel OpenAI API
     9→ * 4. Parsing réponse JSON
    10→ * 5. Validation output LLM (JSON Schema)
    11→ * 6. Calcul score global (formule canonique serveur)
    12→ * 7. Détermination décision (logique serveur)
    13→ * 8. Détection enrichissement
    14→ * 9. Retour réponse conforme
    15→ */
    16→
    17→import { NextResponse } from 'next/server';
    18→import OpenAI from 'openai';
    19→import { validateAnalysisInput, validateLlmRawOutput } from '@/lib/analysis/validators';
    20→import { calculateGlobalScore } from '@/lib/analysis/scoring';
    21→import { determineDecision } from '@/lib/analysis/decision';
    22→import { computeEnrichmentDecision } from '@/lib/analysis/enrichment';
    23→import { CANONICAL_WEIGHTS, SCHEMA_VERSION } from '@/lib/analysis/constants';
    24→import { assembleSystemPrompt, buildUserMessage, CURRENT_VERSION } from '@/lib/analysis/prompts/registry';
    25→import type { AnalysisOutput, AnalysisAxes, ApiError } from '@/lib/analysis/types';
    26→
    27→// ─── OpenAI API client ──────────────────────────────────────────
    28→const openai = new OpenAI({
    29→  apiKey: process.env.OPENAI_API_KEY,
    30→});
    31→
    32→const AI_MODEL = process.env.AI_MODEL || 'gpt-4.1-mini';
    33→const AI_TEMPERATURE = parseFloat(process.env.AI_TEMPERATURE || '0.2');
    34→const AI_TIMEOUT_MS = parseInt(process.env.AI_TIMEOUT_MS || '30000', 10);
    35→
    36→// ═══════════════════════════════════════════════════════════════════
    37→// POST /api/analysis
    38→// ═══════════════════════════════════════════════════════════════════
    39→
    40→export async function POST(req: Request) {
    41→  const startTime = Date.now();
    42→
    43→  try {
    44→    // ─── 1. Parse request body ──────────────────────────────────
    45→    let body: unknown;
    46→    try {
    47→      body = await req.json();
    48→    } catch {
    49→      return errorResponse(400, 'INPUT_SCHEMA_INVALID', 'Request body is not valid JSON');
    50→    }
    51→
    52→    // ─── 2. Validate input against canonical schema ─────────────
    53→    const inputValidation = validateAnalysisInput(body);
    54→    if (!inputValidation.valid) {
    55→      return errorResponse(400, 'INPUT_SCHEMA_INVALID', inputValidation.errors!.join('; '));
    56→    }
    57→
    58→    const input = inputValidation.data!;
    59→
    60→    // ─── 3. Check idea state ────────────────────────────────────
    61→    if (input.idea.state !== 'CAPTURED' && input.idea.state !== 'ANALYZED') {
    62→      return errorResponse(409, 'IDEA_STATE_CONFLICT', `Idea state "${input.idea.state}" is not valid for initial analysis`);
    63→    }
    64→
    65→    // ─── 4. Assemble prompts ────────────────────────────────────
    66→    const systemPrompt = assembleSystemPrompt(CURRENT_VERSION);
    67→    const userMessage = buildUserMessage({
    68→      text: input.inputs.text?.content,
    69→      links: input.inputs.links,
    70→      files: input.inputs.files,
    71→      experienceLevel: input.context?.experience_level,
    72→    });
    73→
    74→    // ─── 5. Call OpenAI API ─────────────────────────────────────
    75→    let llmResponse: string;
    76→    try {
    77→      const completion = await openai.chat.completions.create({
    78→        model: AI_MODEL,
    79→        max_tokens: 4096,
    80→        temperature: AI_TEMPERATURE,
    81→        messages: [
    82→          { role: 'system', content: systemPrompt },
    83→          { role: 'user', content: userMessage },
    84→        ],
    85→      });
    86→
    87→      // Extract text content
    88→      const content = completion.choices[0]?.message?.content;
    89→      if (!content) {
    90→        return errorResponse(500, 'ANALYSIS_OUTPUT_INVALID', 'LLM returned no text content');
    91→      }
    92→      llmResponse = content;
    93→    } catch (error: unknown) {
    94→      const err = error as Error & { status?: number };
    95→      if (err.status === 429) {
    96→        return errorResponse(429, 'AI_RATE_LIMITED', 'AI API rate limit exceeded');
    97→      }
    98→      if (err.name === 'TimeoutError' || err.message?.includes('timeout')) {
    99→        return errorResponse(504, 'AI_TIMEOUT', 'AI analysis timed out');
   100→      }
   101→      console.error('OpenAI API error:', err);
   102→      return errorResponse(500, 'AI_CALL_FAILED', `OpenAI API error: ${err.message}`);
   103→    }
   104→
   105→    // ─── 6. Parse JSON response ─────────────────────────────────
   106→    let parsedLlm: unknown;
   107→    try {
   108→      // Handle potential markdown code block wrapping
   109→      let jsonStr = llmResponse.trim();
   110→      if (jsonStr.startsWith('```json')) {
   111→        jsonStr = jsonStr.slice(7);
   112→      } else if (jsonStr.startsWith('```')) {
   113→        jsonStr = jsonStr.slice(3);
   114→      }
   115→      if (jsonStr.endsWith('```')) {
   116→        jsonStr = jsonStr.slice(0, -3);
   117→      }
   118→      parsedLlm = JSON.parse(jsonStr.trim());
   119→    } catch {
   120→      console.error('LLM JSON parse error. Raw response:', llmResponse.substring(0, 500));
   121→      return errorResponse(500, 'ANALYSIS_OUTPUT_INVALID', 'LLM output is not valid JSON');
   122→    }
   123→
   124→    // ─── 7. Validate LLM output against schema ─────────────────
   125→    const llmValidation = validateLlmRawOutput(parsedLlm);
   126→    if (!llmValidation.valid) {
   127→      console.error('LLM output validation errors:', llmValidation.errors);
   128→      return errorResponse(500, 'ANALYSIS_OUTPUT_INVALID', `LLM output does not match schema: ${llmValidation.errors!.join('; ')}`);
   129→    }
   130→
   131→    const llmData = llmValidation.data!;
   132→
   133→    // ─── 8. Calculate global score (canonical formula, SERVER-SIDE) ──
   134→    const analysis = llmData.analysis as AnalysisAxes;
   135→    const globalScore = calculateGlobalScore(analysis);
   136→
   137→    // ─── 9. Determine decision (canonical rules, SERVER-SIDE) ───
   138→    const decisionResult = determineDecision(
   139→      globalScore,
   140→      analysis,
   141→      llmData.decision.confidence_level
   142→    );
   143→
   144→    // ─── 10. Detect enrichment triggers ─────────────────────────
   145→    const enrichment = computeEnrichmentDecision(
   146→      analysis,
   147→      globalScore,
   148→      llmData.decision.confidence_level
   149→    );
   150→
   151→    // ─── 11. Determine inputs_used ──────────────────────────────
   152→    const inputsUsed: ('text' | 'voice' | 'link' | 'file')[] = [];
   153→    if (input.inputs.text) {
   154→      inputsUsed.push(input.inputs.text.source === 'voice_transcript' ? 'voice' : 'text');
   155→    }
   156→    if (input.inputs.links && input.inputs.links.length > 0) {
   157→      inputsUsed.push('link');
   158→    }
   159→    if (input.inputs.files && input.inputs.files.length > 0) {
   160→      inputsUsed.push('file');
   161→    }
   162→
   163→    // ─── 12. Assemble canonical output ──────────────────────────
   164→    const analysisId = crypto.randomUUID();
   165→
   166→    const output: AnalysisOutput = {
   167→      meta: {
   168→        schema_version: SCHEMA_VERSION,
   169→        analysis_id: analysisId,
   170→        timestamp: new Date().toISOString(),
   171→        orchestrator_version: `v${CURRENT_VERSION.replace('v', '')}`,
   172→        model: AI_MODEL,
   173→      },
   174→      idea: {
   175→        idea_id: input.idea.idea_id,
   176→        title: llmData.idea.title,
   177→        raw_summary: llmData.idea.raw_summary,
   178→        inputs_used: inputsUsed.length > 0 ? inputsUsed : ['text'],
   179→      },
   180→      analysis,
   181→      scores: {
   182→        global_score: globalScore,
   183→        weights: CANONICAL_WEIGHTS,
   184→      },
   185→      decision: {
   186→        recommendation: decisionResult.recommendation,
   187→        confidence_level: llmData.decision.confidence_level,
   188→        summary: llmData.decision.summary,
   189→      },
   190→      risks: llmData.risks as AnalysisOutput['risks'],
   191→      levers: llmData.levers as AnalysisOutput['levers'],
   192→      enrichment,
   193→      lab_orientation: llmData.lab_orientation as AnalysisOutput['lab_orientation'],
   194→    };
   195→
   196→    // ─── 13. Log for traceability ───────────────────────────────
   197→    const duration = Date.now() - startTime;
   198→    console.log(JSON.stringify({
   199→      event: 'analysis_complete',
   200→      request_id: input.meta.request_id,
   201→      analysis_id: analysisId,
   202→      prompt_version: CURRENT_VERSION,
   203→      model: AI_MODEL,
   204→      schema_version: SCHEMA_VERSION,
   205→      global_score: globalScore,
   206→      recommendation: decisionResult.recommendation,
   207→      enrichment_required: enrichment.required,
   208→      duration_ms: duration,
   209→      success: true,
   210→    }));
   211→
   212→    return NextResponse.json(output, { status: 200 });
   213→
   214→  } catch (error: unknown) {
   215→    const err = error as Error;
   216→    console.error('Unexpected analysis error:', err);
   217→    return errorResponse(500, 'INTERNAL_ERROR', `Unexpected error: ${err.message}`);
   218→  }
   219→}
   220→
   221→// ═══════════════════════════════════════════════════════════════════
   222→// ERROR HELPER
   223→// ═══════════════════════════════════════════════════════════════════
   224→
   225→function errorResponse(status: number, code: string, message: string): NextResponse<ApiError> {
   226→  return NextResponse.json(
   227→    {
   228→      error: {
   229→        code,
   230→        message,
   231→        details: { schema_version: SCHEMA_VERSION },
   232→      },
   233→    },
   234→    { status }
   235→  );
   236→}
   237→

